insert into login_bonus_message_data values (560, 60004, 2, 0, 3, 1, 0, '', '今日の運勢は中吉！\u3000大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！', 0, 0, '');
insert into login_bonus_message_data values (561, 60004, 2, 0, 3, 1, 0, '', '今日の運勢は中吉！\u3000健康に気を遣って気持ちのいい一年を！\\n体に不調があるときは遠慮なく言いなさい、隅々まで調べてあげる', 0, 0, '');
