insert into login_bonus_message_data values (563, 60004, 2, 0, 3, 1, 0, '', '今日の運勢は中吉！\u3000誰かに尽くすことで掴める幸せもあるかも？\\n人事を尽くして天命を待つ！\u3000さ、年始もバリバリ働きますわよ♪', 0, 0, '');
